import React, { useEffect, useState, useCallback } from 'react';
import { Borrow, Book, Member } from '../types';
import api from '../utils/api';

const SC: any = { borrowed:'#f59e0b', returned:'#10b981', overdue:'#ef4444', lost:'#8b5cf6' };

export default function Borrows() {
  const [borrows, setBorrows] = useState<Borrow[]>([]);
  const [total, setTotal]     = useState(0);
  const [page, setPage]       = useState(1);
  const [sf, setSf]           = useState('');
  const [loading, setLoading] = useState(true);
  const [modal, setModal]     = useState(false);
  const [books, setBooks]     = useState<Book[]>([]);
  const [members, setMembers] = useState<Member[]>([]);
  const [form, setForm]       = useState({ book_id:'', member_id:'', due_date:'' });
  const [saving, setSaving]   = useState(false);
  const [error, setError]     = useState('');
  const [msg, setMsg]         = useState('');

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const { data } = await api.get('/borrows', { params: { status:sf, page, limit:10 } });
      setBorrows(data.data); setTotal(data.total);
    } finally { setLoading(false); }
  }, [sf, page]);

  useEffect(() => { load(); }, [load]);

  const openModal = async () => {
    const [b,m] = await Promise.all([api.get('/books',{params:{limit:100}}), api.get('/members',{params:{limit:100}})]);
    setBooks(b.data.data.filter((bk:Book)=>bk.available_copies>0));
    setMembers(m.data.data.filter((mb:Member)=>mb.status==='active'));
    const d=new Date(); d.setDate(d.getDate()+14);
    setForm({ book_id:'', member_id:'', due_date:d.toISOString().split('T')[0] });
    setError(''); setModal(true);
  };

  const saveBorrow = async () => {
    if (!form.book_id||!form.member_id||!form.due_date) { setError('All fields required!'); return; }
    setSaving(true); setError('');
    try { await api.post('/borrows',{book_id:Number(form.book_id),member_id:Number(form.member_id),due_date:form.due_date}); setModal(false); load(); }
    catch(e:any) { setError(e.response?.data?.message||'Error'); }
    finally { setSaving(false); }
  };

  const returnBook = async (id:number) => {
    if (!window.confirm('Mark as returned?')) return;
    const { data } = await api.put(`/borrows/${id}/return`);
    setMsg(data.fine>0 ? `Returned! Fine: ৳${data.fine}` : 'Book returned successfully!');
    setTimeout(()=>setMsg(''), 4000);
    load();
  };

  const filters = ['','borrowed','returned','overdue'];

  return (
    <div className="page-enter" style={{ padding:'32px 36px', width:'100%' }}>

      <div style={{ display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:28 }}>
        <div>
          <h1 style={{ fontFamily:"'Playfair Display',serif",fontSize:32,fontWeight:700,color:'var(--text)' }}>Borrows</h1>
          <p style={{ color:'var(--text-muted)',fontSize:14,marginTop:4 }}>{total} borrow records</p>
        </div>
        <button onClick={openModal} className="btn-primary">+ Issue Book</button>
      </div>

      {msg && <div style={{ background:'rgba(16,185,129,0.12)',color:'#10b981',border:'1px solid rgba(16,185,129,0.2)',padding:'12px 16px',borderRadius:10,fontSize:13,fontWeight:600,marginBottom:16 }}>{msg}</div>}

      {/* Filter tabs */}
      <div style={{ display:'flex',gap:8,marginBottom:20,flexWrap:'wrap' }}>
        {filters.map(f=>(
          <button key={f||'all'} onClick={()=>{setSf(f);setPage(1);}}
            style={{ padding:'9px 20px', background:sf===f?'#c9a84c':'var(--bg2)', color:sf===f?'#1a1a2e':'var(--text-dim)', border:sf===f?'none':'1px solid var(--border)', borderRadius:10, fontSize:13, fontWeight:sf===f?700:500, cursor:'pointer', fontFamily:'inherit', textTransform:'capitalize', transition:'all .2s' }}>
            {f||'All'}
          </button>
        ))}
      </div>

      {/* Table */}
      <div style={{ background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:16,overflow:'hidden' }}>
        <table className="tbl">
          <thead>
            <tr>{['Book','Member','Borrow Date','Due Date','Status','Fine','Actions'].map(h=><th key={h}>{h}</th>)}</tr>
          </thead>
          <tbody>
            {loading ? (
              <tr><td colSpan={7} style={{ textAlign:'center',padding:60 }}>
                <div style={{ width:28,height:28,border:'3px solid #c9a84c',borderTopColor:'transparent',borderRadius:'50%',animation:'spin 1s linear infinite',margin:'0 auto' }}/>
              </td></tr>
            ) : borrows.length ? borrows.map(b=>(
              <tr key={b.id}>
                <td>
                  <div style={{ fontSize:14,fontWeight:600,color:'var(--text)' }}>{b.title}</div>
                  <div style={{ fontSize:12,color:'var(--text-muted)' }}>{b.author}</div>
                </td>
                <td>
                  <div style={{ fontSize:13,color:'var(--text)' }}>{b.member_name}</div>
                  <div style={{ fontSize:11,fontFamily:'monospace',color:'#c9a84c' }}>{b.member_code}</div>
                </td>
                <td style={{ color:'var(--text-dim)',fontSize:13 }}>{b.borrow_date?.split('T')[0]}</td>
                <td style={{ fontSize:13,fontWeight:b.status==='overdue'?700:400,color:b.status==='overdue'?'#ef4444':'var(--text-dim)' }}>{b.due_date?.split('T')[0]}</td>
                <td>
                  <span style={{ fontSize:11,fontWeight:700,padding:'4px 11px',borderRadius:99,background:(SC[b.status]||'#6b7280')+'22',color:SC[b.status]||'#6b7280',textTransform:'capitalize' }}>
                    {b.status}
                  </span>
                </td>
                <td style={{ fontWeight:700,color:b.fine_amount>0?'#ef4444':'var(--text-muted)',fontSize:13 }}>
                  {b.fine_amount>0?`৳${Number(b.fine_amount).toFixed(2)}`:'—'}
                </td>
                <td>
                  {(b.status==='borrowed'||b.status==='overdue') ? (
                    <button onClick={()=>returnBook(b.id)} style={{ padding:'6px 13px',background:'rgba(16,185,129,0.15)',color:'#10b981',border:'1px solid rgba(16,185,129,0.25)',borderRadius:7,fontSize:12,cursor:'pointer',fontWeight:700 }}>Return</button>
                  ) : <span style={{ color:'var(--text-muted)',fontSize:13 }}>—</span>}
                </td>
              </tr>
            )) : (
              <tr><td colSpan={7} style={{ textAlign:'center',padding:60,color:'var(--text-muted)',fontSize:14,fontStyle:'italic' }}>No borrows found</td></tr>
            )}
          </tbody>
        </table>
      </div>

      {Math.ceil(total/10)>1 && (
        <div style={{ display:'flex',alignItems:'center',justifyContent:'center',gap:10,marginTop:20 }}>
          <button onClick={()=>setPage(p=>Math.max(1,p-1))} disabled={page===1} className="btn-ghost" style={{ opacity:page===1?0.4:1 }}>← Prev</button>
          <span style={{ fontSize:13,color:'var(--text-muted)' }}>Page {page} of {Math.ceil(total/10)}</span>
          <button onClick={()=>setPage(p=>Math.min(Math.ceil(total/10),p+1))} disabled={page===Math.ceil(total/10)} className="btn-ghost" style={{ opacity:page===Math.ceil(total/10)?0.4:1 }}>Next →</button>
        </div>
      )}

      {/* Issue Modal */}
      {modal && (
        <div style={{ position:'fixed',inset:0,background:'rgba(0,0,0,0.75)',backdropFilter:'blur(6px)',zIndex:1000,display:'flex',alignItems:'center',justifyContent:'center',padding:20 }}>
          <div style={{ background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:20,padding:28,width:'100%',maxWidth:420 }}>
            <div style={{ display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:22 }}>
              <h2 style={{ fontFamily:"'Playfair Display',serif",fontSize:20,fontWeight:700,color:'var(--text)' }}>Issue Book</h2>
              <button onClick={()=>setModal(false)} style={{ background:'var(--bg3)',border:'1px solid var(--border)',color:'var(--text-dim)',width:32,height:32,borderRadius:8,cursor:'pointer',fontSize:16 }}>✕</button>
            </div>
            {error && <div style={{ background:'rgba(239,68,68,0.1)',color:'#ef4444',border:'1px solid rgba(239,68,68,0.2)',padding:'10px 14px',borderRadius:9,fontSize:13,marginBottom:14 }}>{error}</div>}
            <div style={{ display:'grid',gap:14 }}>
              <div>
                <label style={{ display:'block',fontSize:12,fontWeight:600,color:'var(--text-muted)',marginBottom:6 }}>Book (available only) *</label>
                <select className="field" value={form.book_id} onChange={e=>setForm(f=>({...f,book_id:e.target.value}))}>
                  <option value="">Choose book...</option>
                  {books.map(b=><option key={b.id} value={b.id}>{b.title} ({b.available_copies} left)</option>)}
                </select>
              </div>
              <div>
                <label style={{ display:'block',fontSize:12,fontWeight:600,color:'var(--text-muted)',marginBottom:6 }}>Member (active only) *</label>
                <select className="field" value={form.member_id} onChange={e=>setForm(f=>({...f,member_id:e.target.value}))}>
                  <option value="">Choose member...</option>
                  {members.map(m=><option key={m.id} value={m.id}>{m.name} ({m.member_id})</option>)}
                </select>
              </div>
              <div>
                <label style={{ display:'block',fontSize:12,fontWeight:600,color:'var(--text-muted)',marginBottom:6 }}>Due Date *</label>
                <input className="field" type="date" value={form.due_date} onChange={e=>setForm(f=>({...f,due_date:e.target.value}))} />
              </div>
            </div>
            <div style={{ display:'flex',gap:10,marginTop:20 }}>
              <button onClick={()=>setModal(false)} className="btn-ghost" style={{ flex:1 }}>Cancel</button>
              <button onClick={saveBorrow} disabled={saving} className="btn-primary" style={{ flex:1 }}>{saving?'Issuing...':'Issue Book'}</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
